// ✅ UPDATED: src/pages/HomeScreen.js
// Fully wired to QR → redirect → API → UI → Official Control

import React, { useEffect, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
  Pressable,
  ActivityIndicator,
} from "react-native";
import { useNavigation, useRoute } from "@react-navigation/native";
import SecretCodeModal from "../components/SecretCodeModal";
import { useTranslation } from "../i18n";

// ===== ASSETS (UNCHANGED) =====
const taxiImg = require("../../assets/taxi.png");
const cityLogo = require("../../assets/urban.png");
const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const route = useRoute();
  const { lang, setLang, t } = useTranslation();

  // =============================
  // 1️⃣ READ REF FROM REDIRECT
  // =============================
  // Redirect lands on: /verify?ref=CE508NO
  const plateRef = route?.params?.ref ?? null;

  // =============================
  // 2️⃣ STATE
  // =============================
  const [langOpen, setLangOpen] = useState(false);
  const [codeModalOpen, setCodeModalOpen] = useState(false);

  const [loading, setLoading] = useState(true);
  const [vehicle, setVehicle] = useState(null);
  const [error, setError] = useState(null);

  // =============================
  // 3️⃣ FETCH VEHICLE DATA
  // =============================
  useEffect(() => {
    if (!plateRef) {
      setLoading(false);
      return;
    }

    setLoading(true);
    setError(null);

    fetch(
      `https://api.taxidevilleyaounde.com/api/vehicles/${plateRef}/qr`
    )
      .then((res) => res.json())
      .then((json) => {
        if (!json?.success) {
          throw new Error("Vehicle not found");
        }
        setVehicle(json);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setError(true);
        setLoading(false);
      });
  }, [plateRef]);

  // =============================
  // 4️⃣ SECRET CODE CONFIRM
  // =============================
  const handleConfirmCode = (code) => {
    console.log("Secret code entered:", code);
    setCodeModalOpen(false);

    // ✅ Navigate WITH ref
    navigation.navigate("official_control_screen", {
      ref: plateRef,
    });
  };

  // =============================
  // FLAGS
  // =============================
  const FLAGS = {
    fr: "🇫🇷",
    en: "🇬🇧",
  };

  // =============================
  // RENDER
  // =============================
  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.screen}>
        {/* ===== Language Dropdown ===== */}
        <View style={styles.langRow}>
          <View style={styles.langDropdownWrap}>
            <Pressable
              onPress={() => setLangOpen((v) => !v)}
              style={styles.langDropdownBtn}
            >
              <Text style={styles.langDropdownText}>
                {FLAGS[lang]} {lang === "fr" ? "FR" : "EN"}
              </Text>
              <Text style={styles.langDropdownCaret}>
                {langOpen ? "▲" : "▼"}
              </Text>
            </Pressable>

            {langOpen && (
              <View style={styles.langDropdownMenu}>
                <Pressable
                  onPress={() => {
                    setLang("fr");
                    setLangOpen(false);
                  }}
                  style={styles.langDropdownItem}
                >
                  <Text style={styles.langDropdownItemText}>
                    {FLAGS.fr} {t("lang.fr")}
                  </Text>
                </Pressable>

                <Pressable
                  onPress={() => {
                    setLang("en");
                    setLangOpen(false);
                  }}
                  style={styles.langDropdownItem}
                >
                  <Text style={styles.langDropdownItemText}>
                    {FLAGS.en} {t("lang.en")}
                  </Text>
                </Pressable>
              </View>
            )}
          </View>
        </View>

        {/* ===== HERO ===== */}
        <View style={styles.heroWrap}>
          <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
        </View>

        {/* ===== LOADING / ERROR ===== */}
        {loading && (
          <ActivityIndicator size="large" color="#2F7D3A" />
        )}

        {error && (
          <Text style={{ color: "red", marginTop: 12 }}>
            {t("errors.vehicleNotFound")}
          </Text>
        )}

        {!loading && vehicle && (
          <>
            {/* ===== VERIFIED ===== */}
            <View style={styles.statusRow}>
              <Image
                source={tickCircle}
                style={styles.smallTick}
                resizeMode="contain"
              />
              <Text style={styles.statusText}>
                {t("home.verified")}
              </Text>
            </View>

            {/* ===== PLATE ===== */}
            <View style={styles.plateWrap}>
              <View style={styles.plateBox}>
                <Text style={styles.plateText}>
                  {vehicle.identificationVehicule?.immatriculation ??
                    plateRef}
                </Text>
              </View>
            </View>

            {/* ===== OFFICIAL CONTROL BUTTON ===== */}
            <TouchableOpacity
              activeOpacity={0.92}
              style={styles.officialBtn}
              onPress={() => {
                setLangOpen(false);
                setCodeModalOpen(true);
              }}
            >
              <Image
                source={shieldLock}
                style={styles.btnIcon}
                resizeMode="contain"
              />
              <Text style={styles.btnText}>
                {t("home.officialControl")}
              </Text>
            </TouchableOpacity>
          </>
        )}

        {/* ===== BOTTOM LOGO ===== */}
        <View style={styles.logoWrap}>
          <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
        </View>

        {/* ===== SECRET CODE MODAL ===== */}
        <SecretCodeModal
          visible={codeModalOpen}
          onClose={() => setCodeModalOpen(false)}
          onConfirm={handleConfirmCode}
        />
      </View>
    </SafeAreaView>
  );
}

/* =============================
   STYLES (UNCHANGED)
============================= */

const PLATE_WIDTH = 220;
const PLATE_HEIGHT = 40;

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#F5F5F5" },

  screen: {
    flex: 1,
    paddingTop: 14,
    paddingHorizontal: 18,
    alignItems: "center",
    justifyContent: "flex-start",
  },

  /* Language */
  langRow: {
    width: "100%",
    flexDirection: "row",
    justifyContent: "flex-end",
    marginBottom: 6,
    zIndex: 999,
  },

  langDropdownWrap: { position: "relative" },

  langDropdownBtn: {
    height: 34,
    minWidth: 92,
    paddingHorizontal: 12,
    borderRadius: 18,
    backgroundColor: DARK_GREEN,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    gap: 10,
  },

  langDropdownText: {
    color: "#FFFFFF",
    fontSize: 14,
    fontWeight: "800",
  },

  langDropdownCaret: {
    color: "rgba(255,255,255,0.9)",
    fontSize: 12,
    fontWeight: "900",
  },

  langDropdownMenu: {
    position: "absolute",
    top: 40,
    right: 0,
    width: 170,
    borderRadius: 14,
    backgroundColor: "#FFFFFF",
    overflow: "hidden",
    elevation: 8,
  },

  langDropdownItem: {
    paddingVertical: 12,
    paddingHorizontal: 14,
  },

  langDropdownItemText: {
    fontSize: 14,
    fontWeight: "700",
    color: "#111827",
  },

  /* Hero */
  heroWrap: { width: "100%", alignItems: "center" },
  taxi: { width: "100%", height: 200 },

  /* Status */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 6,
    gap: 12,
  },
  smallTick: { width: 56, height: 56 },
  statusText: { fontSize: 30, fontWeight: "600", color: GREEN },

  /* Plate */
  plateWrap: { marginTop: 10 },
  plateBox: {
    width: PLATE_WIDTH,
    height: PLATE_HEIGHT,
    borderRadius: 16,
    borderWidth: 3,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
    alignItems: "center",
    justifyContent: "center",
  },
  plateText: {
    fontSize: 30,
    fontWeight: "600",
    letterSpacing: 1,
    color: "#111827",
  },

  /* Button */
  officialBtn: {
    marginTop: 12,
    width: "72%",
    height: 40,
    backgroundColor: DARK_GREEN,
    borderRadius: 16,
    alignItems: "center",
    justifyContent: "center",
  },
  btnIcon: {
    position: "absolute",
    left: 16,
    width: 30,
    height: 30,
  },
  btnText: { color: "#FFFFFF", fontSize: 20, fontWeight: "700" },

  /* Logo */
  logoWrap: { marginTop: 10, alignItems: "center", flex: 1 },
  logo: { width: 220, height: 210 },
});
